using System.Diagnostics;using ScraperBackendService.Core.Logging;namespace ScraperBackendService.Middleware;/// <summary>/// Memory monitoring middleware that samples memory usage periodically to reduce per-request overhead./// Triggers GC.Collect only at critical thresholds with rate limiting./// </summary>public class MemoryOptimizationMiddleware{    private readonly RequestDelegate _next;    private readonly ILogger<MemoryOptimizationMiddleware> _logger;    private static long _lastGcTicks = DateTime.UtcNow.Ticks;    private static long _requestCount;    private const long CRITICAL_MEMORY_THRESHOLD = 1_024_000_000; // 1GB    private const int GC_COOLDOWN_MINUTES = 5;    private const int SAMPLE_INTERVAL = 50; // Check memory every N requests    public MemoryOptimizationMiddleware(RequestDelegate next, ILogger<MemoryOptimizationMiddleware> logger)    {        _next = next;        _logger = logger;    }    public async Task InvokeAsync(HttpContext context)    {        await _next(context);        // Only check memory every SAMPLE_INTERVAL requests to reduce overhead        var count = Interlocked.Increment(ref _requestCount);        if (count % SAMPLE_INTERVAL != 0)            return;        var memoryBytes = GC.GetTotalMemory(false);        if (memoryBytes > CRITICAL_MEMORY_THRESHOLD && TryAcquireGcCooldown())        {            _logger.LogWarning("HighMemory: process at {MemoryMB}MB, triggering GC", memoryBytes / 1024 / 1024);            GC.Collect(2, GCCollectionMode.Optimized, blocking: false);        }    }    private static bool TryAcquireGcCooldown()    {        var now = DateTime.UtcNow;        var lastTicks = Interlocked.Read(ref _lastGcTicks);        if (now.Ticks - lastTicks < TimeSpan.FromMinutes(GC_COOLDOWN_MINUTES).Ticks)            return false;        return Interlocked.CompareExchange(ref _lastGcTicks, now.Ticks, lastTicks) == lastTicks;    }}